pm.test("Status code is valid for DELETE outcome", function () {
    pm.expect(pm.response.code).to.be.oneOf([200, 202, 204, 404]);
});

pm.test("Response time is less than 2000ms", function () {
    pm.expect(pm.response.responseTime).to.be.below(2000);
});

pm.test("If response is HTML, treat it as likely wrong endpoint", function () {
    const contentType = pm.response.headers.get("Content-Type") || "";
    const bodyText = pm.response.text();

    if (contentType.includes("text/html") || bodyText.trim().startsWith("<!DOCTYPE html") || bodyText.trim().startsWith("<html")) {
        pm.expect.fail("Received HTML instead of API JSON. The request URL may be wrong. Current URL: " + pm.request.url.toString());
    } else {
        pm.expect(true).to.eql(true);
    }
});

pm.test("Parse JSON only when response is JSON", function () {
    const contentType = pm.response.headers.get("Content-Type") || "";
    if (contentType.includes("application/json")) {
        pm.response.to.have.jsonBody();
    } else {
        pm.expect(true).to.eql(true);
    }
});

pm.test("404 is acceptable only for missing resource API response, not HTML page", function () {
    if (pm.response.code === 404) {
        const contentType = pm.response.headers.get("Content-Type") || "";
        pm.expect(contentType).to.not.include("text/html");
    } else {
        pm.expect(true).to.eql(true);
    }
});
